/* ── 슬라이더 노브 위에 라벨을 배치하는 헬퍼 ──
 *  LVGL vertical slider 의 노브는 bar 영역 안에서 움직이되,
 *  value=max 일 때 노브 "anchor" 가 bar top 에 위치하고 노브 자체는
 *  pad_top 만큼 위로 연장된다. → label 을 노브 중심에 두려면
 *  knob_h/2 만큼 위로 보정 필요.                                            */
static void slider_label_follow_knob(lv_obj_t *label, lv_obj_t *slider)
{
    int val = lv_slider_get_value(slider);
    int mn  = lv_slider_get_min_value(slider);
    int mx  = lv_slider_get_max_value(slider);
    if (mx == mn) return;

    lv_coord_t sy = lv_obj_get_style_y(slider, 0);   /* slider y 오프셋 (-50) */
    lv_coord_t sh = lv_obj_get_height(slider);        /* 120 */
    lv_coord_t sw = lv_obj_get_width(slider);         /* 25 */
    lv_coord_t bar_top = sy - sh / 2;                 /* -110 */

    /* knob 높이는 vertical slider 에서 slider 폭과 비슷 (square knob). */
    lv_coord_t knob_h = sw;
    float ratio = (float)(val - mn) / (float)(mx - mn);
    /* knob 중심 y = bar_top + (1 - ratio) * sh - knob_h/2
     *   ratio=1 (max): bar_top - knob_h/2  (knob 이 bar top 위로 연장)
     *   ratio=0 (min): bar_top + sh - knob_h/2  (knob 이 bar bottom 안쪽) */
    lv_coord_t knob_y = bar_top + (lv_coord_t)((1.0f - ratio) * (float)sh) - knob_h / 2;
    lv_obj_set_y(label, knob_y);
}

