        /* Level: 내부 0-9, 표시 1-10, 노브 위에 따라다님 */
        { char buf[8]; lv_snprintf(buf, sizeof(buf), "%d", (int)lv_slider_get_value(target) + 1);
          lv_label_set_text(ui_Label2, buf); }
