        /* 드래그 중 update_center_value() 생략 — release 에서 한 번만 갱신 (응답성 향상) */

        if (s_rs485_syncing) {
            /* RS485 동기화 중: 슬라이더 라벨만 갱신, STBY 전환 안함 */
            return;
        }

        /* READY → STBY 자동 전환 (사용자 터치 시에만) */
