/* ═══════════════════════════════════════════════════════════
 *  RS485 → UI 동기화 콜백 (LVGL 스레드에서 50ms 주기 실행)
 *
 *  rs485_process()가 B/R/S/P/N 커맨드 수신 시
 *  로컬 상태를 업데이트하고 g_ui_update_pending=1 설정.
 *  이 타이머가 LVGL 스레드에서 UI를 갱신한다.
 * ═══════════════════════════════════════════════════════════*/
static void ui_rs485_sync_cb(lv_timer_t *timer)
{
    (void)timer;
    extern volatile uint8_t g_ui_update_pending;
    if (!g_ui_update_pending) return;
    g_ui_update_pending = 0;

    extern volatile uint8_t g_gui_ready;
    extern volatile float   g_needle_depth_mm;

    /* ── 가드 플래그 ON: 슬라이더 이벤트가 STBY로 되돌리지 않도록 ── */
    s_rs485_syncing = 1;

    /* ── PWR 변경 감지 시 중앙 값 표시를 Level 로 전환 ── */
    {
        int old_pwr = lv_slider_get_value(ui_Slider2);
        int new_pwr = (int)g_rf_power;
        if (new_pwr != old_pwr) s_active_slider = 0;
    }

    /* ── 슬라이더 먼저 업데이트 (이벤트 발생해도 가드가 차단) ── */

    /* PWR 슬라이더 (Slider2, 0~9, 표시 1~10) */
    lv_slider_set_value(ui_Slider2, (int32_t)g_rf_power, LV_ANIM_OFF);
    { char buf[8]; lv_snprintf(buf, sizeof(buf), "%d", (int)g_rf_power + 1);
      lv_label_set_text(ui_Label2, buf); }
    slider_label_follow_knob(ui_Label2, ui_Slider2);

    /* NEEDLE 슬라이더 (Slider1) — g_needle_depth_mm(0.5~3.5) → 내부 0~6 반영
     *  (s_rs485_syncing 가드로 위 슬라이더 이벤트는 깊이쓰기 없이 라벨만 갱신) */
    {
        int sv = (int)((g_needle_depth_mm * 10.0f - 5.0f) / 5.0f + 0.5f);
        if (sv < 0) sv = 0; else if (sv > 6) sv = 6;
        lv_slider_set_value(ui_Slider1, (int32_t)sv, LV_ANIM_OFF);
        int dv = sv * 5 + 5;
        char buf[8]; lv_snprintf(buf, sizeof(buf), "%d.%d", dv / 10, dv % 10);
        lv_label_set_text(ui_Label1, buf);
        slider_label_follow_knob(ui_Label1, ui_Slider1);
    }

    /* 중앙 상단 값 갱신 */
    update_center_value();

    /* ── READY/STBY 버튼 (마지막에 설정 — 슬라이더가 덮어쓰지 못함) ── */
    {
        uint8_t was_checked = lv_obj_has_state(ui_ImgButton1, LV_STATE_CHECKED) ? 1 : 0;
        if (g_gui_ready) {
            if (!was_checked)
                lv_obj_add_state(ui_ImgButton1, LV_STATE_CHECKED);
        } else {
            if (was_checked)
                lv_obj_clear_state(ui_ImgButton1, LV_STATE_CHECKED);
        }
        /* 상태 변경 시 사운드 출력 (READY↔STBY 전환) */
        if (was_checked != g_gui_ready) {
            Speaker_Play(g_gui_ready ? SND_READY : SND_STBY);
        }
    }
    lv_obj_invalidate(ui_ImgButton1);
    lv_obj_t *lbl = lv_obj_get_child(ui_ImgButton1, 0);
    if (lbl) lv_label_set_text(lbl, g_gui_ready ? "TREAT" : "STBY");

    /* ── 가드 플래그 OFF ── */
    s_rs485_syncing = 0;
}

